 1	/**
 2	 * Read-path id-backfill normalization (ADR 0006 consequence, registration-launch
 3	 * Branch 2 sub-commit 2.1).
 4	 *
 5	 * Every CMS list item now carries a *required* `id: ListItemId` (a `nanoid`) so
 6	 * the editor can address it by identity rather than by array position. But every
 7	 * `content/site.json` already published BEFORE this change has no ids, so a
 8	 * required `id` would make the live document FAIL decode on the next read — the
 9	 * deploy would break the public site on its own content.
10	 *
11	 * The fix is a one-shot repair at the read boundary: before the document is
12	 * Schema-decoded, `backfillListItemIds` walks the parsed (untrusted) JSON and
13	 * assigns a fresh `nanoid` to any list item that lacks an `id`. It is a pure
14	 * structural normalization — NOT a parallel schema and NOT validation:
15	 *   - `derive-dont-sync`: there is one decode boundary; this only fills the gap
16	 *     a pre-ids document leaves, so the decoded value is always id-complete.
17	 *   - `make-operations-idempotent`: an item that already has an `id` key is left
18	 *     untouched (even a *bad* id is left for the decoder to reject — backfill is
19	 *     for absence, not repair), so re-running on an already-migrated document is
20	 *     a no-op. The first admin publish persists the backfilled ids; from then on
21	 *     the normalization changes nothing.
22	 *   - `boundary-discipline`: it runs only over already-parsed JSON inside the
23	 *     read path, never mutates its input, and hands a fresh value to the decoder
24	 *     which remains the sole gate that brands the ids. The input is `unknown`
25	 *     (raw parsed JSON), so the walk narrows defensively and never trusts shape.
26	 *
27	 * The list-item locations are the id-bearing structs the schema names today
28	 * (`Speaker`, `Seminar`, `Hotel`, `TeamMember`); Branch 3+ widens them as the
29	 * Conference / Page schemas grow id-bearing lists, and this walk grows with
30	 * them. The walk descends only into the arrays/objects that are actually present
31	 * and the expected shape, so a malformed document still reaches the decoder
32	 * (which rejects it) rather than throwing here.
33	 *
34	 * Branch 3.1 grows the Conference with a *required* `hotels: IdListArray(Hotel)`.
35	 * That is the same read-safety hazard as the required `id` itself: a
36	 * `content/site.json` published BEFORE 3.1 has no `hotels` key, so a required
37	 * field would FAIL decode on the next read and silently discard the live
38	 * CMS-authored content. Absence of an *empty-able* list normalizes to `[]`
39	 * (idempotent: a conference already carrying `hotels` keeps it, ids and all),
40	 * which is the one structural gap a pre-3.1 document leaves. (The sibling URL
41	 * fields — `registrationUrl` / `scheduleUrl` / `mapEmbedUrl` — are
42	 * `OptionFromOptionalKey`, so their absence already decodes to `Option.none()`
43	 * and needs no backfill.)
44	 */
45	
46	import { newListItemId } from './schema';
47	import type { Json } from './admin-form';
48	
49	const isObject = (value: unknown): value is { readonly [key: string]: Json } =>
50	  typeof value === 'object' && value !== null && !Array.isArray(value);
51	
52	/** Assign a fresh id to a list item that has no `id` key; else leave it alone. */
53	const withId = (item: Json): Json => {
54	  if (!isObject(item)) return item;
55	  if ('id' in item) return item;
56	  return { id: newListItemId(), ...item };
57	};
58	
59	/** Backfill ids on every element of `value` when it is an array of items. */
60	const backfillItems = (value: unknown): readonly Json[] | undefined =>
61	  Array.isArray(value) ? value.map(withId) : undefined;
62	
63	/**
64	 * Return a copy of the parsed `SiteContent` JSON with a fresh id assigned to any
65	 * id-less list item (`conferences[].speakers[]`, `conferences[].seminars[]`,
66	 * `conferences[].hotels[]`, `team[]`) and an empty `hotels: []` supplied to any
67	 * conference that predates 3.1 and lacks the (required) key. Items already
68	 * carrying an `id` — and a `hotels` array that is already present — are
69	 * untouched (idempotent). A value that is not the expected shape is returned
70	 * as-is so the decoder — not this normalizer — is the one to reject it.
71	 */
72	export const backfillListItemIds = (document: unknown): unknown => {
73	  if (!isObject(document)) return document;
74	
75	  const next: Record<string, Json> = { ...document };
76	
77	  const conferences = document['conferences'];
78	  if (Array.isArray(conferences)) {
79	    next['conferences'] = conferences.map((conference: Json) => {
80	      if (!isObject(conference)) return conference;
81	      const conf: Record<string, Json> = { ...conference };
82	      const speakers = backfillItems(conference['speakers']);
83	      if (speakers !== undefined) conf['speakers'] = speakers;
84	      const seminars = backfillItems(conference['seminars']);
85	      if (seminars !== undefined) conf['seminars'] = seminars;
86	      // `hotels` is a *required* (Branch 3.1) id-keyed list. A pre-3.1 document
87	      // has no key: supply `[]`. A present `hotels` is backfilled like any other
88	      // id list (and left as-is when already id-complete) — never overwritten.
89	      const hotels = backfillItems(conference['hotels']);
90	      conf['hotels'] = hotels !== undefined ? hotels : [];
91	      return conf;
92	    });
93	  }
94	
95	  const team = backfillItems(document['team']);
96	  if (team !== undefined) next['team'] = team;
97	
98	  return next;
99	};

