486	function useCardRotation(
487	  ref: React.RefObject<HTMLDivElement | null>,
488	  isActive?: boolean,
489	) {
490	  const position = useMotionValue(20);
491	  const rotate = useMotionValue(0);
492	  React.useEffect(() => {
493	    const scrollContainer = document.querySelector('[data-scroll-container]');
494	
495	    if (!scrollContainer) return;
496	    if (!ref.current) return;
497	
498	    let isInViewport = false;
499	
500	    const observer = new IntersectionObserver(
501	      (entries) => {
502	        const entry = entries[0];
503	        if (entry?.isIntersecting) {
504	          isInViewport = true;
505	        } else {
506	          isInViewport = false;
507	        }
508	      },
509	      {
510	        root: scrollContainer,
511	
512	        threshold: 0,
513	      },
514	    );
515	
516	    observer.observe(ref.current!);
517	
518	    const initialCardRect = ref.current?.getBoundingClientRect();
519	
520	    if (!initialCardRect) return;
521	    const bounds = [
522	      initialCardRect.top,
523	      initialCardRect.top + initialCardRect.height,
524	    ];
525	
526	    function onScroll() {
527	      const containerEle = document.querySelector(
528	        '[data-scroll-container]',
529	      ) as HTMLElement;
530	      if (!containerEle) return;
531	      if (!isInViewport) return;
532	      const scrollY = containerEle.scrollTop + containerEle.clientHeight;
533	
534	      const nextPosition = transform(scrollY, bounds, [20, 4]);
535	      const nextRotate = transform(scrollY, bounds, [0, -3]);
536	
537	      position.set(nextPosition);
538	      rotate.set(nextRotate);
539	    }
540	
541	    scrollContainer.addEventListener('scroll', onScroll);
542	    return () => {
543	      observer.disconnect();
544	      scrollContainer.removeEventListener('scroll', onScroll);
545	    };
546	  }, [position, rotate, ref, isActive]);
547	
548	  return {
549	    position,
550	    rotate,
551	  };
552	}
