 62	  const { url } = yield* ReactRouterContext;
 63	  const submission = yield* SubmissionContext;
 64	  const env = yield* Env.Service;
 65	  if (Option.isNone(env.sendgrid)) {
 66	    return yield* notFound();
 67	  }
 68	  const sendgrid = yield* Sendgrid.Service;
 69	  const toast = yield* Toast;
 70	
 71	  const parsed = parseSchema(schema, submission.payload);
 72	  if (Result.isFailure(parsed)) {
 73	    return yield* formValidationError(formatSchemaResult(parsed) ?? {});
 74	  }
 75	  const data = parsed.success;
 76	
 77	  const result = yield* Effect.exit(sendgrid.subscribe(data.email, data.name));
 78	  if (result._tag === "Failure") {
 79	    yield* Effect.logError("newsletter subscribe failed", result.cause);
 80	    return yield* formValidationError({
 81	      formErrors: ["main.newsletter.error" satisfies TranslationKey],
 82	    });
 83	  }
 84	
 85	  return yield* toast.redirect(url.pathname, {
 86	    type: "success",
 87	    title: "main.newsletter.success.title" satisfies TranslationKey,
 88	    description: "main.newsletter.success.description" satisfies TranslationKey,
 89	    form: "newsletter-form",
 90	  });
 91	});
