496	function useCardRotation(
497	  ref: React.RefObject<HTMLDivElement | null>,
498	  isActive?: boolean,
499	) {
500	  const position = useMotionValue(20);
501	  const rotate = useMotionValue(0);
502	  React.useEffect(() => {
503	    const scrollContainer = document.querySelector('[data-scroll-container]');
504	
505	    if (!scrollContainer) return;
506	    if (!ref.current) return;
507	
508	    let isInViewport = false;
509	
510	    const observer = new IntersectionObserver(
511	      (entries) => {
512	        const entry = entries[0];
513	        if (entry?.isIntersecting) {
514	          isInViewport = true;
515	        } else {
516	          isInViewport = false;
517	        }
518	      },
519	      {
520	        root: scrollContainer,
521	
522	        threshold: 0,
523	      },
524	    );
525	
526	    observer.observe(ref.current!);
527	
528	    const initialCardRect = ref.current?.getBoundingClientRect();
529	
530	    if (!initialCardRect) return;
531	    const bounds = [
532	      initialCardRect.top,
533	      initialCardRect.top + initialCardRect.height,
534	    ];
535	
536	    function onScroll() {
537	      const containerEle = document.querySelector(
538	        '[data-scroll-container]',
539	      ) as HTMLElement;
540	      if (!containerEle) return;
541	      if (!isInViewport) return;
542	      const scrollY = containerEle.scrollTop + containerEle.clientHeight;
543	
544	      const nextPosition = transform(scrollY, bounds, [20, 4]);
545	      const nextRotate = transform(scrollY, bounds, [0, -3]);
546	
547	      position.set(nextPosition);
548	      rotate.set(nextRotate);
549	    }
550	
551	    scrollContainer.addEventListener('scroll', onScroll);
552	    return () => {
553	      observer.disconnect();
554	      scrollContainer.removeEventListener('scroll', onScroll);
555	    };
556	  }, [position, rotate, ref, isActive]);
557	
558	  return {
559	    position,
560	    rotate,
561	  };
562	}
